changeSet.sql:
DO $$ BEGIN
    IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = 'app_read') THEN
        CREATE ROLE app_read;
    END IF;
    IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = 'app_write') THEN
        CREATE ROLE app_write;
    END IF;
    IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = 'app_admin') THEN
        CREATE ROLE app_admin;
    END IF;
END $$;

GRANT SELECT ON exchange_rates, supported_currencies TO app_read;

GRANT SELECT, INSERT, UPDATE
    ON exchange_rates, supported_currencies, api_provider_keys
    TO app_write;
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO app_write;

GRANT ALL PRIVILEGES ON ALL TABLES IN SCHEMA public TO app_admin;
GRANT ALL PRIVILEGES ON ALL SEQUENCES IN SCHEMA public TO app_admin;

changeSet.rollback:
DROP ROLE IF EXISTS app_read;
DROP ROLE IF EXISTS app_write;
DROP ROLE IF EXISTS app_admin;
